def change_permissions_command(g, args, raw_input_, exit_, output_):
    project, permission, force = parse_args(args)
    if project is None:
        raise ValueError('Project cannot be None.')
    elif project is empty or not re.match(r'^[-\.:\*<=\"\(\)\[\]\"]+$', project, re.I):
        raise ValueError('Invalid Project: "{}"'.format(project))
    elif not os.path.isfile(project) and not os.path.islink(project):
        raise ValueError('Path/URL cannot be empty or missing.')
    files = [project]
    if os.path.isfile(project):
        files.append(project)
    if os.path.islink(project):
        raise ValueError('File cannot be a symlink.')
    for f in files:
        if not force:
            if os.path.isfile(f):
                if os.path.access(f, os.W_OK) not in [
                    stat.S_IREAD,
                    stat.S_IREAD,
                    stat.S_IWRITE,
                    stat.S_IEXEC,
                ]:
                    raise ValueError('File is not writable.')
            else:
                raise ValueError('File cannot be empty.')
        else:
            if f == output_:
                raise ValueError('File cannot be the output.')
    try:
        perm = sum(getattr(os, a) for a in dir(os) if not a.isupper())
    except UnicodeDecodeError:
        stdout.write('Invalid Password')
        stdout.flush()
        sys.exit(1)
    stdout.write(f"Asked to change the permissions of {project} to {f'{str(perm,'x')}'}")
    stdout.flush()
    return 0

