def validate_http_secure_context(self, value):
    try:
        from OpenSSL import SSL
    except Exception:    
        raise AuthError("IIS SSL requires OpenSSL to be installed.")
    if not self._in_tls:
        raise AuthError("IIS_Transport must be used in TLS mode.")
    if not isinstance(value, SSL.Context):
        raise AuthError("Invalid context provided.")
    return value

